#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAXN 50
#define MAXVAL 2500
int grid[MAXN][MAXN];
int visited[MAXN][MAXN];
int n;
int bfs(int t) {
    int queue[MAXN * MAXN][2];
    int front = 0, rear = 0;
    queue[rear][0] = 0;
    queue[rear][1] = 0;
    rear++;
    visited[0][0] = 1;
    while (front < rear) {
        int x = queue[front][0];
        int y = queue[front][1];
        front++;
        if (x == n - 1 && y == n - 1) return 1;
        if (x > 0 && grid[x - 1][y] <= t && !visited[x - 1][y]) {
            queue[rear][0] = x - 1;
            queue[rear][1] = y;
            rear++;
            visited[x - 1][y] = 1;
        }
        if (x < n - 1 && grid[x + 1][y] <= t && !visited[x + 1][y]) {
            queue[rear][0] = x + 1;
            queue[rear][1] = y;
            rear++;
            visited[x + 1][y] = 1;
        }
        if (y > 0 && grid[x][y - 1] <= t && !visited[x][y - 1]) {
            queue[rear][0] = x;
            queue[rear][1] = y - 1;
            rear++;
            visited[x][y - 1] = 1;
        }
        if (y < n - 1 && grid[x][y + 1] <= t && !visited[x][y + 1]) {
            queue[rear][0] = x;
            queue[rear][1] = y + 1;
            rear++;
            visited[x][y + 1] = 1;
        }
    }
    return 0;
}
int findMinimumSwimTime() {
    int low = 0, high = MAXVAL;
    while (low < high) {
        int mid = (low + high) / 2;
        memset(visited, 0, sizeof(visited));
        if (bfs(mid)) high = mid;
        else low = mid + 1;
    }
    return low;
}
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &n);
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < n; j++) {
                scanf("%d", &grid[i][j]);
            }
        }
        printf("%d\n", findMinimumSwimTime());
    }
    return 0;
}

