int n;
bool bfs(int t) {
    queue<pair<int, int>> q;
    q.push({0, 0});
    visited[0][0] = true;
    while (!q.empty()) {
        int x = q.front().first;
        int y = q.front().second;
        q.pop();
        if (x == n - 1 && y == n - 1) return true;
        if (x > 0 && grid[x - 1][y] <= t && !visited[x - 1][y]) {
            q.push({x - 1, y});
            visited[x - 1][y] = true;
        }
        if (x < n - 1 && grid[x + 1][y] <= t && !visited[x + 1][y]) {
            q.push({x + 1, y});
            visited[x + 1][y] = true;
        }
        if (y > 0 && grid[x][y - 1] <= t && !visited[x][y - 1]) {
            q.push({x, y - 1});
            visited[x][y - 1] = true;
        }
        if (y < n - 1 && grid[x][y + 1] <= t && !visited[x][y + 1]) {
            q.push({x, y + 1});
            visited[x][y + 1] = true;
        }
    }
    return false;
}
