import java.util.Queue;
import java.util.LinkedList;
import java.util.Scanner;
public class Main {
    static final int MAXN = 50;
    static final int MAXVAL = 2500;
    static int[][] grid = new int[MAXN][MAXN];
    static boolean[][] visited = new boolean[MAXN][MAXN];
    static int n;
    static boolean bfs(int t) {
        Queue<int[]> q = new LinkedList<>();
        q.offer(new int[] {0, 0});
        visited[0][0] = true;
        while (!q.isEmpty()) {
            int[] curr = q.poll();
            int x = curr[0];
            int y = curr[1];
            if (x == n - 1 && y == n - 1) return true;
            if (x > 0 && grid[x - 1][y] <= t && !visited[x - 1][y]) {
                q.offer(new int[] {x - 1, y});
                visited[x - 1][y] = true;
            }
            if (x < n - 1 && grid[x + 1][y] <= t && !visited[x + 1][y]) {
                q.offer(new int[] {x + 1, y});
                visited[x + 1][y] = true;
            }
            if (y > 0 && grid[x][y - 1] <= t && !visited[x][y - 1]) {
                q.offer(new int[] {x, y - 1});
                visited[x][y - 1] = true;
            }
            if (y < n - 1 && grid[x][y + 1] <= t && !visited[x][y + 1]) {
                q.offer(new int[] {x, y + 1});
                visited[x][y + 1] = true;
            }
        }
        return false;
    }
    static int findMinimumSwimTime() {
        int low = 0, high = MAXVAL;
        while (low < high) {
            int mid = (low + high) / 2;
            for (int i = 0; i < n; i++) {
                for (int j = 0; j < n; j++) {
                    visited[i][j] = false;
                }
            }
            if (bfs(mid)) high = mid;
            else low = mid + 1;
        }
        return low;
    }
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            n = sc.nextInt();
            for (int i = 0; i < n; i++) {
                for (int j = 0; j < n; j++) {
                    grid[i][j] = sc.nextInt();
                }
            }
            System.out.println(findMinimumSwimTime());
        }
    }
}

